class BatchQRCodePDFExporter{constructor(options={}){this.options={fileName:options.fileName||"二维码.pdf",items:options.items||[],qrSize:options.qrSize||80,textFontSize:options.textFontSize||16,textMargin:options.textMargin||10,...options,};this.dependenciesLoaded=false;this.loadingPromise=null;}async startExport(){try{if(!this.options.items||this.options.items.length===0){throw new Error("没有数据可生成 PDF");}this.showMessage("正在准备生成 PDF...","info");await this.ensureDependencies();await this.generatePDF();this.showMessage(`PDF 生成成功：${this.options.fileName}`,"success");}catch(error){console.error("生成 PDF 失败:",error);this.showMessage("生成 PDF 失败："+error.message,"error");}}async ensureDependencies(){if(this.dependenciesLoaded)return;if(this.loadingPromise)return this.loadingPromise;this.loadingPromise=this.loadDependencies();await this.loadingPromise;this.dependenciesLoaded=true;}loadDependencies(){const libs=[{name:"qrcode-generator",global:"qrcode",url:"https://cdn.jsdelivr.net/npm/qrcode-generator@1.4.4/qrcode.min.js",},{name:"jspdf",global:"jspdf",url:"https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js",},];const loadScript=(url)=>{return new Promise((resolve,reject)=>{if(document.querySelector(`script[src="${url}"]`)){resolve();return;}const script=document.createElement("script");script.src=url;script.onload=resolve;script.onerror=()=>reject(new Error(`加载失败：${url}`));document.head.appendChild(script);});};const toLoad=libs.filter((lib)=>!window[lib.global]).map((lib)=>loadScript(lib.url));if(toLoad.length===0){return Promise.resolve();}return Promise.all(toLoad);}generateQRCodeDataURL(text){const qr=window.qrcode(0,"M");qr.addData(text);qr.make();const matrixSize=qr.getModuleCount();const cellSize=8;const canvasSize=matrixSize*cellSize;const canvas=document.createElement("canvas");canvas.width=canvasSize;canvas.height=canvasSize;const ctx=canvas.getContext("2d");ctx.fillStyle="#ffffff";ctx.fillRect(0,0,canvasSize,canvasSize);ctx.fillStyle="#000000";for(let row=0;row<matrixSize;row++){for(let col=0;col<matrixSize;col++){if(qr.isDark(row,col)){ctx.fillRect(col*cellSize,row*cellSize,cellSize,cellSize);}}}return canvas.toDataURL("image/png");}async generatePDF(){const{jsPDF}=window.jspdf;const doc=new jsPDF();const pageWidth=doc.internal.pageSize.getWidth();const pageHeight=doc.internal.pageSize.getHeight();const{items,fileName,qrSize,textFontSize,textMargin}=this.options;for(let i=0;i<items.length;i++){const{code,url}=items[i];if(!code||!url){console.warn(`跳过第${i+1}项：缺少 code 或 url`);continue;}const imgData=this.generateQRCodeDataURL(url);if(i>0){doc.addPage();}const textHeightApprox=textFontSize*0.35;const totalHeight=qrSize+textMargin+textHeightApprox;const startY=(pageHeight-totalHeight)/2;const qrX=(pageWidth-qrSize)/2;const qrY=startY;doc.addImage(imgData,"PNG",qrX,qrY,qrSize,qrSize);doc.setFontSize(textFontSize);const textWidth=(doc.getStringUnitWidth(code)*textFontSize)/doc.internal.scaleFactor;const textX=(pageWidth-textWidth)/2;const textY=qrY+qrSize+textMargin+textHeightApprox/2;doc.text(code,textX,textY);}doc.save(fileName);}showMessage(message,type="info"){console.log(`[${type.toUpperCase()}]`,message);}}if(typeof window!=="undefined"){window.BatchQRCodePDFExporter=BatchQRCodePDFExporter;}
